type Graph = {
  [node: string]: string[];
};

class CycleError extends Error {
  constructor(message: string = 'Cycle detected in graph') {
    super(message);
    this.name = 'CycleError';
  }
}

export function toposort(graph: Graph): string[] {
  const visited = new Set<string>();
  const inProgress = new Set<string>();
  const result: string[] = [];

  function dfs(node: string): void {
    if (visited.has(node)) {
      return;
    }

    if (inProgress.has(node)) {
      throw new CycleError(`Cycle detected involving node: ${node}`);
    }

    inProgress.add(node);

    const neighbors = graph[node] || [];
    for (const neighbor of neighbors) {
      dfs(neighbor);
    }

    inProgress.delete(node);
    visited.add(node);
    result.push(node);
  }

  // Visit all nodes
  for (const node in graph) {
    if (!visited.has(node)) {
      dfs(node);
    }
  }

  // Also visit any nodes that are only targets (appear in edges but not as keys)
  for (const node in graph) {
    const neighbors = graph[node] || [];
    for (const neighbor of neighbors) {
      if (!visited.has(neighbor)) {
        dfs(neighbor);
      }
    }
  }

  return result;
}
